class Solution {
public:
    int minimumCost(string s) {
        int n = s.size();
        int res = 0;
        int cnt = 0;
        for (int i = 1; i < n; i++) {
            if (s[i] != s[i - 1]) {
                cnt++;
            }
        }
        return min(cnt, n - cnt);
    }
};
